import React from "react";

const MovieCard = ({ movie, onSelect }) => {
  const title = typeof movie === "string" ? movie : movie.title || movie.name || "Untitled";
  const subtitle = typeof movie === "object"
    ? [movie.year, movie.genres?.[0]].filter(Boolean).join("  ")
    : "";
  const matchLabel = typeof movie === "object" && movie.match ? `${movie.match}% Match` : "Recommended";

  return (
    <article className="movie-card" onClick={onSelect}>
      <div className="movie-card-poster">
        <span>{title.charAt(0)}</span>
      </div>
      <div className="movie-card-body">
        <p className="movie-card-meta">{matchLabel}</p>
        <h3 className="movie-card-title">{title}</h3>
        {subtitle && <p className="movie-card-subtitle">{subtitle}</p>}
      </div>
    </article>
  );
};

export default MovieCard;
